{
  "collection": "articles",
  "filter": {
    "article_id": {
      "$gte": "180",
      "$lt": "220"
    }
  },
  "projection": {
    "_id": 0,
    "article_id": 1,
    "title": 1,
    "description": 1
  }
}
'''

